t.script:

let certOriginalData = {};
let certOriginalText = '';
let certIsEditMode = false;

/* Issue 8: fix last-updated timezone */
(function fixCertTimezone() {
    var el = document.getElementById('certLastUpdated');
    if (!el) return;
    var raw = el.textContent.trim().replace(/\u00a0/g,' ');
    if (!raw || raw === 'Never') return;
    try {
        var m = raw.match(/(\d{1,2})\s+(\w+),?\s+(\d{4})\s+at\s+(\d{1,2}):(\d{2})\s*(AM|PM)/i);
        if (m) {
            var months = {jan:0,feb:1,mar:2,apr:3,may:4,jun:5,jul:6,aug:7,sep:8,oct:9,nov:10,dec:11};
            var monIdx = months[m[2].toLowerCase().substring(0,3)];
            var hr = parseInt(m[4],10);
            var isPM = m[6].toUpperCase()==='PM';
            if (isPM && hr < 12) hr += 12;
            if (!isPM && hr === 12) hr = 0;
            var dt = new Date(Date.UTC(parseInt(m[3],10), monIdx, parseInt(m[1],10), hr, parseInt(m[5],10)));
            if (!isNaN(dt.getTime())) {
                el.textContent = dt.toLocaleString(undefined,{day:'2-digit',month:'short',year:'numeric',hour:'2-digit',minute:'2-digit',hour12:true});
            }
        }
    } catch(e) {}
})();

document.addEventListener('DOMContentLoaded', function() {
    /* snapshot for change detection */
    certOriginalText = (document.getElementById('certText').value || '').trim();
    /* ensure file inputs start disabled */
    document.querySelectorAll('.cert-file-input').forEach(fi => fi.setAttribute('disabled','disabled'));
    /* ensure view actions shown */
    document.getElementById('certViewActions').style.display = 'block';
    document.getElementById('certFormActions').style.display = 'none';
});

/* Issue 14: toggle via the form-switch checkbox */
function certToggleEditMode(checkbox) {
    if (checkbox.checked) {
        certEnableEdit();
    } else {
        certCancelEdit();
    }
}

function certEnableEdit() {
    certIsEditMode = true;
    certStoreOriginal();
    /* sync toggle */
    var tog = document.getElementById('certEditToggle');
    if (tog) tog.checked = true;

    const inputs = document.querySelectorAll('#certificationForm input, #certificationForm textarea');
    inputs.forEach(input => {
        if (input.type !== 'hidden') {
            input.removeAttribute('readonly');
            input.removeAttribute('disabled');
        }
    });
    /* enable file inputs */
    document.querySelectorAll('#certificationForm .cert-file-input').forEach(fi => fi.removeAttribute('disabled'));

    document.getElementById('certFormActions').style.display = 'block';
    document.getElementById('certViewActions').style.display = 'none';

    /* Issue 10: change Edit button appearance */
    var editBtn = document.getElementById('certEditBtn');
    if (editBtn) {
        editBtn.classList.remove('btn-outline-primary');
        editBtn.classList.add('btn-primary', 'edit-active');
        editBtn.innerHTML = '<i class="fa fa-pencil me-1"></i>Editing Mode ON';
    }

    const disc = document.getElementById('certDisclaimer');
    if (disc) disc.checked = false;
    const btn = document.getElementById('certSaveBtn');
    if (btn) { btn.disabled = true; btn.style.opacity = '0.6'; }
}

function certStoreOriginal() {
    const form = document.getElementById('certificationForm');
    const formData = new FormData(form);
    certOriginalData = {};
    for (let [key, value] of formData.entries()) {
        certOriginalData[key] = value;
    }
}

function certCancelEdit() {
    for (let [key, value] of Object.entries(certOriginalData)) {
        const input = document.querySelector(`[name="${key}"]`);
        if (input && input.type !== 'hidden' && input.type !== 'file') {
            input.value = value;
        }
    }
    certDisableEdit();
    certShowMessage('Changes cancelled.', 'info');
}

function certDisableEdit() {
    certIsEditMode = false;
    const inputs = document.querySelectorAll('#certificationForm input, #certificationForm textarea');
    inputs.forEach(input => {
        if (input.type !== 'hidden' && input.type !== 'file') {
            input.setAttribute('readonly', 'readonly');
        }
    });
    /* disable file inputs */
    document.querySelectorAll('#certificationForm .cert-file-input').forEach(fi => {
        fi.setAttribute('disabled', 'disabled');
        fi.value = '';
    });

    document.getElementById('certFormActions').style.display = 'none';
    document.getElementById('certViewActions').style.display = 'block';

    /* sync toggle off */
    var tog = document.getElementById('certEditToggle');
    if (tog) tog.checked = false;

    /* Issue 10: restore edit button appearance */
    var editBtn = document.getElementById('certEditBtn');
    if (editBtn) {
        editBtn.classList.remove('btn-primary', 'edit-active');
        editBtn.classList.add('btn-outline-primary');
        editBtn.innerHTML = '<i class="fa fa-edit me-1"></i>Edit Certifications';
    }

    const disc = document.getElementById('certDisclaimer');
    if (disc) disc.checked = false;
    const btn = document.getElementById('certSaveBtn');
    if (btn) { btn.disabled = true; btn.style.opacity = '0.6'; }
}

function toggleCertSaveBtn() {
    const checked = document.getElementById('certDisclaimer').checked;
    const btn = document.getElementById('certSaveBtn');
    btn.disabled = !checked;
    btn.style.opacity = checked ? '1' : '0.6';
}

document.getElementById('certificationForm').addEventListener('submit', function (e) {
    e.preventDefault();
    const disc = document.getElementById('certDisclaimer');
    if (disc && !disc.checked) {
        certShowMessage('Please read and accept the Employee Disclaimer before saving.', 'error');
        return;
    }

    /* Issue 12 pattern: detect no-change */
    const currentText = (document.getElementById('certText').value || '').trim();
    const trainingInput = document.querySelector('[name="training_certificates"]');
    const awardsInput = document.querySelector('[name="awards_files"]');
    const hasTrainingFile = trainingInput && trainingInput.files && trainingInput.files.length > 0;
    const hasAwardsFile = awardsInput && awardsInput.files && awardsInput.files.length > 0;

    if (currentText === certOriginalText && !hasTrainingFile && !hasAwardsFile) {
        certShowMessage('No changes detected. Your certification data is already up to date.', 'info');
        return;
    }

    /* Issue 11: show overlay when uploading files */
    const hasAnyFile = hasTrainingFile || hasAwardsFile;
    var overlay = document.getElementById('certUploadOverlay');
    if (hasAnyFile) {
        overlay.style.display = 'flex';
    }

    const formData = new FormData(this);
    fetch('/my/employee/certification', {
        method: 'POST',
        body: formData
    })
    .then(response => {
        if (overlay) overlay.style.display = 'none';
        return response.json();
    })
    .then(data => {
        if (data.success) {
            certOriginalText = currentText;
            certShowMessage('Certifications updated successfully!', 'success');
            certDisableEdit();
        } else {
            certShowMessage('Error: ' + (data.error || 'Unknown error'), 'error');
        }
    })
    .catch(error => {
        if (overlay) overlay.style.display = 'none';
        console.error('Error:', error);
        certShowMessage('Network error. Please try again.', 'error');
    });
});

function certShowMessage(text, type) {
    const container = document.getElementById('certMessageContainer');
    const successMsg = document.getElementById('certSuccessMessage');
    const errorMsg = document.getElementById('certErrorMessage');
    successMsg.style.display = 'none';
    errorMsg.style.display = 'none';
    successMsg.classList.remove('show');
    errorMsg.classList.remove('show');
    if (type === 'success' || type === 'info') {
        document.getElementById('certSuccessText').textContent = text;
        successMsg.style.display = 'block';
        successMsg.classList.add('show');
    } else {
        document.getElementById('certErrorText').textContent = text;
        errorMsg.style.display = 'block';
        errorMsg.classList.add('show');
    }
    container.style.display = 'block';
    container.scrollIntoView({behavior: 'smooth'});
    setTimeout(() => {
        successMsg.classList.remove('show');
        errorMsg.classList.remove('show');
    }, 5000);
}
